import * as React from "react";

export interface TdSectionProps {
  eyebrow?: string;
  headline?: string;
  body?: React.ReactNode;
  cta?: { label: string; href: string };
  surface?: "light" | "dark" | "tinted";
  align?: "left" | "center";
  className?: string;
  children?: React.ReactNode;
}

const surfaceStyle: Record<NonNullable<TdSectionProps["surface"]>, React.CSSProperties> = {
  light: { backgroundColor: "#ffffff", color: "#0f172a" },
  dark: {
    backgroundColor: "var(--td-primary, #2E6554)",
    color: "#ffffff",
  },
  tinted: {
    backgroundColor: "var(--td-tint, #F2F6F4)",
    color: "#0f172a",
  },
};

export function TdSection({
  eyebrow,
  headline,
  body,
  cta,
  surface = "light",
  align = "left",
  className = "",
  children,
}: TdSectionProps) {
  const alignment = align === "center" ? "items-center text-center" : "items-start text-left";
  return (
    <section className={`w-full ${className}`.trim()} style={surfaceStyle[surface]}>
      <div className={`mx-auto flex max-w-5xl flex-col ${alignment} gap-6 px-6 py-20 md:py-28`}>
        {eyebrow ? (
          <span
            className="text-xs font-semibold uppercase tracking-[0.2em]"
            style={{ color: surface === "dark" ? "#ffffff" : "var(--td-secondary, #234F98)" }}
          >
            {eyebrow}
          </span>
        ) : null}
        {headline ? (
          <h2 className="max-w-3xl text-3xl font-semibold leading-tight tracking-tight md:text-4xl">
            {headline}
          </h2>
        ) : null}
        {body ? <div className="max-w-2xl text-base leading-relaxed opacity-90">{body}</div> : null}
        {children}
        {cta ? (
          <a
            href={cta.href}
            className="mt-2 inline-flex h-10 items-center rounded-md px-5 text-sm font-medium transition-opacity hover:opacity-90"
            style={{
              backgroundColor:
                surface === "dark" ? "#ffffff" : "var(--td-primary, #2E6554)",
              color: surface === "dark" ? "var(--td-primary, #2E6554)" : "#ffffff",
            }}
          >
            {cta.label}
          </a>
        ) : null}
      </div>
    </section>
  );
}

export default TdSection;
